var body = $json.body || $json;
var reqText = body.requirementsText || body.fullText || '';
if (reqText.length > 120000) reqText = reqText.substring(0, 120000);
return [{ json: { requirementsText: reqText } }];

const raw = ($json.text || $json.response || '').trim();
let result;

try {
  result = JSON.parse(raw);
} catch (e) {
  const m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  const candidate = m ? m[1].trim() : raw;
  try {
    const s = candidate.indexOf('{');
    const e2 = candidate.lastIndexOf('}');
    let jsonStr = candidate.substring(s, e2 + 1);
    jsonStr = jsonStr.replace(/,\s*([\]\}])/g, '$1');
    result = JSON.parse(jsonStr);
  } catch (e3) {
    result = {
      procurement_subject: 'Parse error',
      requirements: [],
      _parse_error: 'JSON parse failed',
      _raw: raw.substring(0, 2000)
    };
  }
}

return [{ json: { requirements: result } }];
